import{_ as a,o,c as n,ag as i}from"./chunks/framework.NIzFHKo_.js";const _=JSON.parse('{"title":"ADR-0002: Single Domain Rule","description":"","frontmatter":{"uid":"49fa3aba-6764-49f2-ba0b-05995fe4d24b ... ..."},"headers":[],"relativePath":"10_core/10_governance/50_decisions/adr-0002_single_domain_rule.md","filePath":"10_core/10_governance/50_decisions/adr-0002_single_domain_rule.md"}'),c={name:"10_core/10_governance/50_decisions/adr-0002_single_domain_rule.md"};function s(d,e,r,t,l,m){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-0002-single-domain-rule" tabindex="-1">ADR-0002: Single Domain Rule <a class="header-anchor" href="#adr-0002-single-domain-rule" aria-label="Permalink to &quot;ADR-0002: Single Domain Rule&quot;">​</a></h1><p><strong>Date</strong>: 2026-03-27 <strong>Status</strong>: Accepted</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Early schema design placed domain logic in the <code>public</code> schema and mixed concerns across tables. This created unclear ownership and made RLS enforcement fragile.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Every domain in QiOS gets <strong>one canonical Postgres schema</strong>. No domain logic lives in <code>public</code>. The mapping is enforced in <code>registry/domain_registry.yaml</code>.</p><p>Rules:</p><ul><li>One schema per domain (e.g., <code>qicase</code>, <code>qivault</code>, <code>qihome</code>)</li><li>All domain tables must carry <code>tenant_id</code> for RLS isolation</li><li><code>public</code> schema is reserved for legacy stubs and global auth-adjacent data only</li><li>Cross-domain access must go through the Platform RBAC layer</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>All new tables are created in their domain schema, never in <code>public</code></li><li>Domain registry must be updated when a new schema is created</li><li>Existing <code>public</code> tables (<code>todos</code>, <code>nods_page</code>) are marked legacy and will not be extended</li></ul>',10)])])}const h=a(c,[["render",s]]);export{_ as __pageData,h as default};
